import type { NextConfig } from "next";

// In dev, run Velite in watch mode so content edits hot-reload.
// For `build`, content is generated by the `velite` step in the build script
// (running it here races webpack and can wipe .velite mid-compile).
const isDev = process.argv.includes("dev");
if (isDev && !process.env.VELITE_STARTED) {
  process.env.VELITE_STARTED = "1";
  import("velite").then(({ build }) => build({ watch: true, clean: false }));
}

const nextConfig: NextConfig = {
  // Pin the workspace root to this project (multiple lockfiles exist on the machine).
  turbopack: { root: __dirname },
  // Inline critical CSS into <head> to cut a render-blocking stylesheet request —
  // Tailwind v4 is the exact use case this flag targets. Kept only if a before/after
  // Lighthouse on the deployed URL shows an FCP/LCP win without a TTFB regression.
  experimental: { inlineCss: true },
  images: {
    formats: ["image/avif", "image/webp"],
    remotePatterns: [
      // github-readme-stats removed: the /projects feed is now first-party
      // (src/lib/github.ts, server-fetched + ISR) — no external <img> embed.
      { protocol: "https", hostname: "img.shields.io" },
    ],
  },
};

export default nextConfig;
